const_facts();
self_.lemma_view();
reveal(is_bit_set);
assert(COMMIT_MASK_BITS == 512) by (compute_only);

// Re-state lemma_view's two ensures so they are present in the proof context
// with their natural triggers. The first forall is triggered on
// `self_@.contains(i)`, the second on `self_@.contains(a*64+b)`. The two
// `forall |t| ...self_@.contains(t)` quantifiers from the implication's
// antecedent (one for r1, one for r2) now share that trigger surface, so any
// concrete `t` z3 picks from either range produces matching bit-level facts.
assert(forall |i: int| self_@.contains(i) ==> {
    let a = i / usize::BITS as int;
    let b = (i % usize::BITS as int) as usize;
    &&& a * 64 + b == i
    &&& is_bit_set(self_.mask[a], b)
});
assert(forall |a: int, b: usize| 0 <= a < 8 && b < 64 && is_bit_set(self_.mask[a], b)
    ==> #[trigger] self_@.contains(a * 64 + b));

// Bit-level membership is downward-bounded: every element of `self_@` lies in
// [0, COMMIT_MASK_BITS). This gives z3 a uniform range trigger to bound the
// `t`s coming out of both forall quantifiers.
assert forall |i: int| self_@.contains(i) implies 0 <= i < COMMIT_MASK_BITS by {
    self_.lemma_view();
    let a = i / usize::BITS as int;
    let b = (i % usize::BITS as int) as usize;
    assert(a * 64 + b == i);
    assert(is_bit_set(self_.mask[a], b));
    assert(0 <= a < 8);
    assert(b < 64);
};
